import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { format } from 'date-fns';
import { FaCar, FaCalendar, FaMapMarkerAlt } from 'react-icons/fa';
import './MyBookings.css';

const MyBookings = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchBookings();
  }, []);

  const fetchBookings = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/bookings/my-bookings');
      setBookings(res.data.data);
    } catch (error) {
      console.error('Error fetching bookings:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleCancelBooking = async (bookingId) => {
    if (!window.confirm('Are you sure you want to cancel this booking?')) return;

    try {
      await axios.delete(`http://localhost:5000/api/bookings/${bookingId}`);
      fetchBookings();
    } catch (error) {
      console.error('Error cancelling booking:', error);
      alert('Failed to cancel booking');
    }
  };

  const getStatusClass = (status) => {
    const classes = {
      pending: 'status-pending',
      confirmed: 'status-confirmed',
      active: 'status-active',
      completed: 'status-completed',
      cancelled: 'status-cancelled'
    };
    return classes[status] || '';
  };

  if (loading) return <div className="loading">Loading bookings...</div>;

  return (
    <div className="my-bookings">
      <div className="container">
        <h1>My Bookings</h1>

        {bookings.length === 0 ? (
          <div className="no-bookings">
            <p>You don't have any bookings yet</p>
            <a href="/cars"><button className="btn btn-primary">Browse Cars</button></a>
          </div>
        ) : (
          <div className="bookings-list">
            {bookings.map(booking => (
              <div key={booking._id} className="booking-card">
                <div className="booking-header">
                  <div className="booking-number">
                    Booking #{booking.confirmationNumber}
                  </div>
                  <span className={`booking-status ${getStatusClass(booking.status)}`}>
                    {booking.status}
                  </span>
                </div>

                <div className="booking-content">
                  <div className="booking-car">
                    <img 
                      src={booking.carId?.images?.[0] || '/placeholder-car.jpg'} 
                      alt={booking.carId?.make} 
                    />
                    <div className="car-details">
                      <h3>
                        <FaCar /> {booking.carId?.make} {booking.carId?.model}
                      </h3>
                      <p>{booking.carId?.year} • {booking.carId?.category}</p>
                    </div>
                  </div>

                  <div className="booking-details">
                    <div className="detail-item">
                      <FaCalendar />
                      <div>
                        <p className="detail-label">Pickup</p>
                        <p className="detail-value">
                          {format(new Date(booking.pickupDate), 'MMM dd, yyyy HH:mm')}
                        </p>
                      </div>
                    </div>
                    <div className="detail-item">
                      <FaCalendar />
                      <div>
                        <p className="detail-label">Dropoff</p>
                        <p className="detail-value">
                          {format(new Date(booking.dropoffDate), 'MMM dd, yyyy HH:mm')}
                        </p>
                      </div>
                    </div>
                    <div className="detail-item">
                      <FaMapMarkerAlt />
                      <div>
                        <p className="detail-label">Location</p>
                        <p className="detail-value">{booking.pickupLocation}</p>
                      </div>
                    </div>
                  </div>

                  <div className="booking-footer">
                    <div className="booking-price">
                      <span className="price-label">Total Price</span>
                      <span className="price-value">${booking.totalPrice}</span>
                    </div>
                    {['pending', 'confirmed'].includes(booking.status) && (
                      <button 
                        onClick={() => handleCancelBooking(booking._id)}
                        className="btn btn-danger"
                      >
                        Cancel Booking
                      </button>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default MyBookings;
